+                    if (stack.items.len < 1) return error.StackUnderflow;
+                    const top = stack.items[stack.items.len - 1];
+                    const dup_val = try std.fmt.allocPrint(self.allocator, "{s}", .{top});
+                    try stack.append(self.allocator, dup_val);
+                } else {
